checker_dsl:
EXISTS (`MC`, `EXPR`) {
  AND {
    EXISTS (`M`) {
      AND {
        (`MC is a method call`),
        (`MC's called method is M`),
        (`M's name is "getMessage"`),
        (`M has no parameters`),
        (`M's declaring type has qualified name "java.lang.Throwable"`)
      }
    },
    (`there exists a data flow path from MC to EXPR`),
    (`EXPR is an HTTP response sink`)
  }
}
